import React, { useState } from "react";
import MainPage from "./components/MainPage";
import LoginPage from "./components/LoginPageTemp";
import RegistryPageTemp from "./components/RegistryPageTemp"; 
import axios from 'axios';
import './App.css';

function App() {
  const [view, setView] = useState('main'); 
  const [file, setFile] = useState(null);
  const [result, setResult] = useState("");
  const [loading, setLoading] = useState(false);


  const handleUpload = async () => {
    if (!file) return alert("Proszę wybrać zdjęcie!");
    setLoading(true);
    setResult("");

    const formData = new FormData();
    formData.append('file', file);

    try {

      const response = await axios.post('http://localhost:8081/api/scan', formData);
      setResult(response.data);
    } catch (error) {
      setResult("Błąd połączenia z serwerem: " + error.message);
    } finally {
      setLoading(false);
    }
  };




  if (view === 'main') {
    return (
      <MainPage 
        onLogin={() => setView('login')}
        onRegister={() => setView('registry')} 
      />
    );
  }


  if (view === 'login') {
    return (
      <LoginPage
        onBack={() => setView('main')}
        onRegister={() => setView('registry')} 
        onLoginSuccess={() => setView('scanner')} 
      />
    );
  }


  if (view === 'registry') {
    return (
      <RegistryPageTemp
        onBack={() => setView('main')}
        onLogin={() => setView('login')} 
      />
    );
  }


  return (
    <div className="App">
      <header className="App-header">
        <button 
          className="back-button"
          onClick={() => setView('main')}
        > 
          ← LOG OUT
        </button>

        <h1 className="logo-top">MoleCheckerAI</h1>

        <div className="scanner-container">
          <p className="scanner-instruction">Upload Image For AI Analysis</p>

          {/* Stylizowany input do plików */}
          <div className="file-upload-wrapper">
            <input 
              type="file" 
              id="file-input" 
              onChange={(e) => setFile(e.target.files[0])} 
            />
          </div>

          <button className="analyze-button" onClick={handleUpload} disabled={loading}>
            {loading ? "Analyzing..." : "Analyze mole"}
          </button>

          {result && (
            <div className="result-box">
              <h3>Result:</h3>
              <p>{result}</p>
            </div>
          )}
        </div>
      </header>
    </div>
  );
}

export default App;
